function [ttlA,ttlS,lblP] = fLabelEsmovV04(nmbStep)%% function label for esm overview%% [ttlA,ttlS,lblP] = fLabelEsmovV01()% gives you labels%% ttlA: title for angle text output% ttlS: title for spectrumd text output% lblP: lable for image plot%%% Written  by Kei Nakamura% Created on Tuesday, December 7th 2010.% Modified on %% ver.1:% ver.2: Friday, February 24th, 2012% add div for each energy (FWHM)% add div for each energy (rms)% ver.4: 2012/7/20 for V10%% main body%% label for angle txt outputttlA = cell(5*nmbStep,1);ttlA{1} = 'angle_mrad';ttlA{2} = 'charge_pC/mrad';ttlA{3} = 'charge+std_pC/mrad';ttlA{4} = 'charge-std_pC/mrad';ttlA{5} = 'std_pC/mrad';%% label for energy txt outputttlS = cell(16*nmbStep,1);ttlS{1} = 'energy_GeV';ttlS{2} = 'charge_pC/GeV';ttlS{3} = 'charge+std_pC/GeV';ttlS{4} = 'charge-std_pC/GeV';ttlS{5} = 'std_pC/GeV';% ttlS{6} = 'peakAngle_mrad';% ttlS{7} = 'peakAngle-std_mrad';% ttlS{8} = 'peakAngle+std_mrad';% ttlS{9} = 'meanAngle_mrad';% ttlS{10} = 'meanAngle-std_mrad';% ttlS{11} = 'meanAngle+std_mrad';% ttlS{12} = 'stdDivg_mrad';% ttlS{13} = 'stdDivg-std_mrad';% ttlS{14} = 'stdDivg+std_mrad';% ttlS{15} = 'meanAngle_mrad';% ttlS{16} = 'stdDivergence_mrad';for ii=1:nmbStep-1    ttlA(ii*5+1:(ii+1)*5) = ttlA(1:5);    ttlS(ii*5+1:(ii+1)*5) = ttlS(1:5);end%% label for plotlblP{1} = 'mrad';lblP{2} = 'MeV';
